# Python: Replay session exactly as it happened
def replay_session(session_data):
    """Replay session exactly for debugging"""

    for step in session_data:
        # Reproduce the exact state
        reproduce_screenshot(step['screenshot'])

        # Execute the exact action
        if step['action']['type'] == 'click':
            click(step['action']['coordinate'][0], step['action']['coordinate'] [medium](https://medium.com/replay-io/session-replay-vs-time-travel-debugging-14a1357e2fc3))
        elif step['action']['type'] == 'type':
            type_text(step['action']['text'])

        # Log what happened
        print(f"Replayed: {step['action']} → {step['response']}")
